window.PERIBAHASA = [{"id": "Sedikit demi sedikit, lama-lama menjadi bukit.", "ja": "塵も積もれば山となる。", "audio": "audio/pb/pb00.mp3"}, {"id": "Ada gula, ada semut.", "ja": "利益あるところに人が集まる。", "audio": "audio/pb/pb01.mp3"}, {"id": "Air tenang menghanyutkan.", "ja": "静かな水は深い（おとなしい人ほど侮れない）。", "audio": "audio/pb/pb02.mp3"}, {"id": "Berakit-rakit ke hulu, berenang-renang ke tepian.", "ja": "先に苦労すれば後で楽になる。", "audio": "audio/pb/pb03.mp3"}, {"id": "Tak ada gading yang tak retak.", "ja": "完璧なものはない。", "audio": "audio/pb/pb04.mp3"}, {"id": "Bagai pinang dibelah dua.", "ja": "うり二つ。", "audio": "audio/pb/pb05.mp3"}, {"id": "Sambil menyelam minum air.", "ja": "一石二鳥。", "audio": "audio/pb/pb06.mp3"}, {"id": "Di mana ada kemauan, di situ ada jalan.", "ja": "意志あるところに道は開ける。", "audio": "audio/pb/pb07.mp3"}, {"id": "Bersatu kita teguh, bercerai kita runtuh.", "ja": "団結は力なり。", "audio": "audio/pb/pb08.mp3"}, {"id": "Malu bertanya, sesat di jalan.", "ja": "聞くは一時の恥、聞かぬは一生の恥。", "audio": "audio/pb/pb09.mp3"}, {"id": "Rajin pangkal pandai.", "ja": "勤勉は賢さのもと。", "audio": "audio/pb/pb10.mp3"}, {"id": "Hemat pangkal kaya.", "ja": "倹約は富のもと。", "audio": "audio/pb/pb11.mp3"}, {"id": "Sudah jatuh, tertimpa tangga.", "ja": "泣きっ面に蜂。", "audio": "audio/pb/pb12.mp3"}, {"id": "Buah jatuh tak jauh dari pohonnya.", "ja": "この親にしてこの子あり。", "audio": "audio/pb/pb13.mp3"}, {"id": "Sepandai-pandai tupai melompat, sekali gawal juga.", "ja": "猿も木から落ちる。", "audio": "audio/pb/pb14.mp3"}, {"id": "Gajah di pelupuk mata tak tampak.", "ja": "灯台下暗し。", "audio": "audio/pb/pb15.mp3"}, {"id": "Besar pasak daripada tiang.", "ja": "収入より支出が多い（分不相応）。", "audio": "audio/pb/pb16.mp3"}, {"id": "Karena nila setitik, rusak susu sebelanga.", "ja": "一つの過ちで全てが台無しになる。", "audio": "audio/pb/pb17.mp3"}, {"id": "Ringan sama dijinjing, berat sama dipikul.", "ja": "苦楽を共にする。", "audio": "audio/pb/pb18.mp3"}, {"id": "Ala bisa karena biasa.", "ja": "習うより慣れよ。", "audio": "audio/pb/pb19.mp3"}, {"id": "Diam itu emas.", "ja": "沈黙は金。", "audio": "audio/pb/pb20.mp3"}, {"id": "Tong kosong nyaring bunyinya.", "ja": "中身のない者ほどよく騒ぐ。", "audio": "audio/pb/pb21.mp3"}, {"id": "Bahasa menunjukkan bangsa.", "ja": "言葉遣いは人柄を表す。", "audio": "audio/pb/pb22.mp3"}, {"id": "Sepi ing pamrih, rame ing gawe.", "ja": "見返りを求めず、よく働く。", "audio": "audio/pb/pb23.mp3"}];
